from zeep import Client
from zeep.exceptions import Fault
import re

def is_valid_input(input_string):
    return bool(re.match("^[a-zA-Z0-9 ]*$", input_string))

def get_policy_details():
    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")

    if not is_valid_input(policy_number) or not is_valid_input(customer_name):
        print("Invalid input. Please use alphanumeric characters and spaces only.")
        return

    client = Client('https://example.com/insurance_service?wsdl')

    try:
        response = client.service.GetPolicyDetails(PolicyNumber=policy_number, CustomerName=customer_name)
        print("Policy Details:", response)
    except Fault as e:
        print("Error occurred:", e)

if __name__ == "__main__":
    get_policy_details()